INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 321, 1, 24001, 0, 125801, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, "リリ");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 322, 1, 24001, 0, 126001, 2, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, "クリア");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 323, 1, 24001, 0, 126101, 3, "んーと。\nこれ、あげる。\nはい", 1, "プレシア");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 324, 2, 24001, 0, 125801, 4, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 1, "リリ");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 325, 2, 24001, 0, 126001, 5, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 1, "クリア");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 326, 2, 24001, 0, 126101, 6, "お兄。\nきてくれて、うれしい", 1, "プレシア");
